```typescript
export async function createRisksFromAnalysis(
  documentId: string,
  risks: Array<{
    title: string;
    description: string;
    category: string;
    subcategory: string | null;
    severity: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
    section: string | null;
    textExcerpt: string | null;
    startOffset?: number | null;
    endOffset?: number | null;
    recommendation: string | null;
    suggestedText: string | null;
    clientMotivation: string | null;
    isCompanyStandardDeviation?: boolean;
    companyStandardReference?: string | null;
    priority?: 'MUST_HAVE' | 'SHOULD_HAVE' | 'NICE_TO_HAVE' | null;
    fallbackPosition?: string | null;
    likelihood?: number | null;
    clauseMatchId?: string;
  }>,
  workspaceId: string,
  tx: Transaction = prisma
): Promise<RiskItem[]> {
  const document = await LegalDocumentRepository.findSummary(documentId, workspaceId, tx);
  if (!document) { throw new AppError('DOCUMENT_NOT_FOUND'); }

  const playbookRules = await tx.playbookRule.findMany({
    where: { workspaceId, isActive: true },
    orderBy: { priority: 'desc' },
    select: { id: true, conditions: true, action: true, actionConfig: true, workspaceId: true },
    take: 200,
  });

  const createdRisks = await RiskItemRepository.createManyAndReturn(
    risks.map((riskData) => ({
      documentId, clauseMatchId: riskData.clauseMatchId,
      title: riskData.title, description: riskData.description,
      category: riskData.category, subcategory: riskData.subcategory,
      severity: riskData.severity, section: riskData.section,
      textExcerpt: riskData.textExcerpt,
      startOffset: riskData.startOffset ?? null,
      endOffset: riskData.endOffset ?? null,
      recommendation: riskData.recommendation, suggestedText: riskData.suggestedText,
      clientMotivation: riskData.clientMotivation,
      isCompanyStandardDeviation: riskData.isCompanyStandardDeviation ?? false,
      companyStandardReference: riskData.companyStandardReference ?? null,
      priority: riskData.priority ?? null,
      fallbackPosition: riskData.fallbackPosition ?? null,
      likelihood: riskData.likelihood ?? null,
      status: 'IDENTIFIED' as const,
    })), tx
  );

  for (const risk of createdRisks) {
    const matchingRule = playbookRules.find((rule) =>
      matchesConditions(risk, rule.conditions as object)
    );
    if (matchingRule) {
      await tx.riskItem.update({ where: { id: risk.id }, data: buildRuleUpdateData(risk, matchingRule) });
    }
  }

  const riskIds = createdRisks.map((r) => r.id);
  const SYNC_TIMEOUT_MS = 15_000;
  Promise.race([
    syncRisksBulk(riskIds),
    new Promise<void>((resolve) => setTimeout(resolve, SYNC_TIMEOUT_MS)),
  ]).catch((err) => {
    logger.warn('[RISK] Meilisearch sync failed (non-blocking)', {
      riskCount: riskIds.length,
      error: err instanceof Error ? err.message : String(err),
    });
  });

